// Calculate WoW changes for each KPI metric
const rows = $input.all().map(i => i.json);
if (rows.length < 2) return [{ json: { error: 'Not enough data rows', rows: rows.length } }];

// Sort by date descending
rows.sort((a, b) => new Date(b.date) - new Date(a.date));

const thisWeek = rows[0];
const lastWeek = rows[1] || {};

const metrics = Object.keys(thisWeek).filter(k => k !== 'date' && !isNaN(Number(thisWeek[k])));

const changes = metrics.map(metric => {
  const current = Number(thisWeek[metric]) || 0;
  const previous = Number(lastWeek[metric]) || 0;
  const change_pct = previous !== 0 ? (((current - previous) / previous) * 100).toFixed(1) : 'N/A';
  const trend = current >= previous ? '📈' : '📉';
  return { metric, current, previous, change_pct, trend };
});

return [{ json: { week_ending: thisWeek.date, changes, raw: thisWeek } }];
